function solve(code, businessLine, isActive) {
    // Define the order of business lines
    const businessOrder = ["electronics", "grocery", "pharmacy", "restaurant"];

    // Filter valid coupons
    const validCoupons = code
        .map((c, i) => {
            // Check if code is not empty and only contains allowed characters
            const isValidCode = c !== "" && /^[a-zA-Z0-9_]+$/.test(c);
            // Check if business line is valid
            const isValidBusiness = businessOrder.includes(businessLine[i]);
            // Check if active
            const isValidActive = isActive[i];

            if (isValidCode && isValidBusiness && isValidActive) {
                return { code: c, businessLine: businessLine[i] };
            }
            return null;
        })
        .filter(c => c !== null);

    // Sort by business line order and then by code lexicographically
    validCoupons.sort((a, b) => {
        const businessIndexA = businessOrder.indexOf(a.businessLine);
        const businessIndexB = businessOrder.indexOf(b.businessLine);

        if (businessIndexA !== businessIndexB) {
            return businessIndexA - businessIndexB;
        }
        return a.code.localeCompare(b.code);
    });

    // Extract the codes in the sorted order
    const result = validCoupons.map(c => c.code);
    return result;
}

