        // Check if active
        bool isValidActive = isActive[i];

        if (isValidCode && isValidBusiness && isValidActive) {
            validCoupons.push_back({code[i], businessLine[i]});
        }
    }

    // Sort by business line order and then by code lexicographically
    sort(validCoupons.begin(), validCoupons.end(), [](const pair<string, string>& a, const pair<string, string>& b) {
        size_t businessIndexA = find(businessOrder.begin(), businessOrder.end(), a.second) - businessOrder.begin();
        size_t businessIndexB = find(businessOrder.begin(), businessOrder.end(), b.second) - businessOrder.begin();

        if (businessIndexA != businessIndexB) {
            return businessIndexA < businessIndexB;
        }
        return a.first < b.first;
    });

    // Extract the codes in the sorted order
    vector<string> result;
    for (const auto& coupon : validCoupons) {
        result.push_back(coupon.first);
    }
    return result;
}
